// // Asynchronous reset functionality: Q is set to 1 and QN is set to 0 on the rising edge of CK when RST is high
module top_module(
    input CK,
    input D,
    input RST,
    output reg Q,     // Changed Q to output reg
    output reg QN     // Changed QN to output reg
);always @(posedge CK or negedge RST) begin
    if (!RST) begin
        Q <= 0;
        QN <= 1;
    end else begin
        Q <= D;
        QN <= ~D;
    end
end

endmodule
